566	    // checkstackGCp → { state.check_stack(n)?; state.gc().check_step(); }  (macros.tsv)
567	    // PORT NOTE: func_idx is a StackIdx and survives any stack reallocation.
568	    state.check_stack(1)?;
569	    state.gc_check_step();
570	
