581	    // Open a slot: shift everything from top down to func_idx up by one.
582	    // C: for (p = L->top.p; p > func; p--) setobjs2s(L, p, p-1)
583	    let top = state.top_idx();
584	    let mut p = top;
585	    while p.0 > func_idx.0 {
586	        let val = state.get_at(p - 1).clone();
587	        state.set_at(p, val);
588	        p = p - 1;
