    n_results: i32,
) -> Result<(), LuaError> {
    // C: ccall(L, func, nResults, nyci)
    // NYCI = 0x10001 increments both the recursion count and the non-yieldable count.
    ccall_inner(state, func_idx, n_results, NYCI)
}

